import{_ as a,o,c as e,a3 as r}from"./chunks/framework.DACwFHq9.js";const c=JSON.parse('{"title":"弹幕播放器","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/danmaku-player.md","filePath":"user-guide/tools/danmaku-player.md","lastUpdated":1778221347000}'),l={name:"user-guide/tools/danmaku-player.md"};function i(s,t,n,d,h,p){return o(),e("div",null,[...t[0]||(t[0]=[r(`<h1 id="弹幕播放器" tabindex="-1">弹幕播放器 <a class="header-anchor" href="#弹幕播放器" aria-label="Permalink to &quot;弹幕播放器&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>弹幕播放器是一个支持 <strong>ASS 格式弹幕</strong> 的高性能视频播放工具。无论你是 B 站视频创作者、番剧收藏爱好者，还是习惯用 ASS 弹幕文件看片的用户，都能用它获得沉浸式的弹幕体验。</p><div class="tip custom-block"><p class="custom-block-title">核心场景</p><p>你从 Bilibili Evolved 导出了 <code>.ass</code> 弹幕文件？想在自己的本地视频上挂载弹幕观看？用弹幕播放器就能实现——不需要联网，不需要第三方弹幕网站，直接把 ASS 弹幕挂到视频上。</p></div><h3 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h3><ul><li><strong>双模式播放</strong>：内置播放器直接播放视频 + 渲染弹幕；外部播放器模式连接 MPC-BE，通过独立覆盖窗口渲染弹幕</li><li><strong>ASS 弹幕解析</strong>：完整解析 Bilibili / Bilibili Evolved 导出的 ASS 格式弹幕文件，支持 <code>\\move</code>、<code>\\pos</code>、<code>\\c</code>、<code>\\b</code> 等标签</li><li><strong>Canvas 高性能渲染</strong>：基于 HTML5 Canvas 的弹幕渲染引擎，二分查找可见弹幕窗口，密度过滤采用稳定哈希算法，流畅不卡顿</li><li><strong>丰富的显示调整</strong>：透明度、字体缩放、滚动速度、显示区域、密度控制、边框样式（发光/描边/阴影）一应俱全</li><li><strong>播放状态同步</strong>：实时同步弹幕与视频进度，支持类型过滤（滚动/固定/彩色弹幕）和屏蔽词过滤</li></ul><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><h3 id="准备工作" tabindex="-1">准备工作 <a class="header-anchor" href="#准备工作" aria-label="Permalink to &quot;准备工作&quot;">​</a></h3><p>你需要准备一个 <code>.ass</code> 格式的弹幕文件，和一个视频文件（MP4、MKV、WebM、AVI、MOV 等常见格式）。</p><p>ASS 弹幕文件可以通过以下方式获取：</p><ul><li>使用 <a href="https://github.com/the1812/Bilibili-Evolved" target="_blank" rel="noreferrer">Bilibili Evolved</a> 浏览器扩展导出 B 站视频的弹幕为 ASS</li><li>使用其他弹幕下载工具获取弹幕后导出为 ASS 格式</li><li>本地已有的 ASS 字幕/弹幕文件</li></ul><h3 id="首次使用-5-步走" tabindex="-1">首次使用 5 步走 <a class="header-anchor" href="#首次使用-5-步走" aria-label="Permalink to &quot;首次使用 5 步走&quot;">​</a></h3><p><strong>第一步：打开工具</strong></p><p>在左侧工具列表中找到 <strong>弹幕播放器</strong>，点击进入。你会看到顶部的模式切换标签页和文件选择区域。</p><blockquote><p>TODO: 截图 - 弹幕播放器整体界面，标注模式切换、文件选择区域和播放器区域</p></blockquote><p><strong>第二步：切换模式（可选）</strong></p><p>默认使用 <strong>内置播放器</strong> 模式。如果你习惯使用 MPC-BE 播放视频，可以切换到 <strong>外部播放器</strong> 模式。</p><blockquote><p>TODO: 截图 - 标注模式切换标签&quot;内置播放器&quot;和&quot;外部播放器&quot;</p></blockquote><p><strong>第三步：加载视频</strong></p><p>在内置播放器模式下，点击视频选择区域或拖入视频文件到 &quot;视频&quot; 区域。</p><blockquote><p>TODO: 截图 - 鼠标指向视频选择区域，展示拖放手势</p></blockquote><p><strong>第四步：加载弹幕</strong></p><p>点击弹幕选择区域或拖入 <code>.ass</code> 弹幕文件到 &quot;弹幕&quot; 区域。加载成功后，底部会显示解析到的弹幕数量（如 &quot;1200 条&quot;）。</p><blockquote><p>TODO: 截图 - 弹幕选择区域，展示加载后的文件名和弹幕数量</p></blockquote><p><strong>第五步：开始观看</strong></p><p>视频加载后自动进入播放状态，弹幕会随着视频进度实时在画面中飘过。你可以在右侧的弹幕设置面板中调整显示效果。</p><blockquote><p>TODO: 截图 - 视频正在播放，弹幕在画面上飘过的效果</p></blockquote><h2 id="功能详解" tabindex="-1">功能详解 <a class="header-anchor" href="#功能详解" aria-label="Permalink to &quot;功能详解&quot;">​</a></h2><h3 id="内置播放器模式" tabindex="-1">内置播放器模式 <a class="header-anchor" href="#内置播放器模式" aria-label="Permalink to &quot;内置播放器模式&quot;">​</a></h3><p>内置播放器模式是弹幕播放器最直接的使用方式——直接在工具内播放视频，Canvas 引擎负责渲染弹幕层。</p><h4 id="文件选择" tabindex="-1">文件选择 <a class="header-anchor" href="#文件选择" aria-label="Permalink to &quot;文件选择&quot;">​</a></h4><p>文件选择区域位于工具顶部，分为两个区域：</p><table tabindex="0"><thead><tr><th>区域</th><th>说明</th></tr></thead><tbody><tr><td>视频</td><td>拖入或点击选择视频文件。支持 <code>.mp4</code>、<code>.mkv</code>、<code>.webm</code>、<code>.avi</code>、<code>.mov</code> 等格式</td></tr><tr><td>弹幕</td><td>拖入或点击选择 ASS 弹幕文件。仅支持 <code>.ass</code> 格式</td></tr></tbody></table><p>两个区域各自有独立的清除按钮（X 图标），方便随时更换文件或弹幕。</p><h4 id="播放控制" tabindex="-1">播放控制 <a class="header-anchor" href="#播放控制" aria-label="Permalink to &quot;播放控制&quot;">​</a></h4><p>内置播放器提供了基础的视频播放控制功能：</p><ul><li><strong>播放/暂停</strong>：控制视频播放状态</li><li><strong>进度条</strong>：拖动跳转到任意时间点</li><li><strong>音量控制</strong>：调节播放音量</li><li><strong>全屏</strong>：全屏观看</li></ul><blockquote><p>TODO: 截图 - 内置播放器的控制栏，标注播放/暂停、进度条、音量、全屏等按钮</p></blockquote><h4 id="弹幕渲染引擎" tabindex="-1">弹幕渲染引擎 <a class="header-anchor" href="#弹幕渲染引擎" aria-label="Permalink to &quot;弹幕渲染引擎&quot;">​</a></h4><p>引擎基于 HTML5 Canvas 实现，具有以下性能优化：</p><ul><li><strong>二分查找</strong>：按弹幕起始时间排序后，每帧通过二分查找快速定位当前可见弹幕，避免全量遍历</li><li><strong>密度过滤稳定哈希</strong>：相同内容弹幕的 hash 值固定，切换帧时不会随机抖动导致弹幕忽隐忽现</li><li><strong>批量渲染</strong>：按字体分组，减少 Canvas 上下文状态切换</li><li><strong>预计算缓存</strong>：不随帧变化的配置项（字体缩放、透明度等）只在配置变更时重新计算</li></ul><h3 id="外部播放器模式" tabindex="-1">外部播放器模式 <a class="header-anchor" href="#外部播放器模式" aria-label="Permalink to &quot;外部播放器模式&quot;">​</a></h3><p>如果你习惯使用 MPC-BE 播放视频，外部播放器模式可以让你在 MPC-BE 的画面上叠加弹幕层，享受&quot;原汁原味&quot;的本地播放体验。</p><blockquote><p>TODO: 截图 - 外部播放器模式整体界面，标注四个区域</p></blockquote><h4 id="前置条件" tabindex="-1">前置条件 <a class="header-anchor" href="#前置条件" aria-label="Permalink to &quot;前置条件&quot;">​</a></h4><p>使用外部播放器模式需要：</p><ol><li><strong>MPC-BE</strong> 播放器已安装并运行</li><li>MPC-BE 的 <strong>Web 接口</strong> 已开启（MPC-BE 设置 &gt; Web Interface &gt; 启用，默认端口 13579）</li></ol><h4 id="连接播放器" tabindex="-1">连接播放器 <a class="header-anchor" href="#连接播放器" aria-label="Permalink to &quot;连接播放器&quot;">​</a></h4><p><strong>第一步：扫描播放器窗口</strong></p><p>点击 <strong>扫描播放器</strong> 按钮，系统会自动搜索当前系统中运行的 MPC-BE 窗口。如果没找到，可以点击下拉菜单中的 &quot;扫描所有窗口&quot; 进行更广泛的搜索。</p><blockquote><p>TODO: 截图 - 扫描播放器按钮和下拉菜单</p></blockquote><p><strong>第二步：选择窗口</strong></p><p>在扫描结果列表中，选择一个播放器窗口。列表中会显示窗口标题和类名，方便区分。</p><blockquote><p>TODO: 截图 - 播放器窗口列表，展示发现的窗口</p></blockquote><p><strong>第三步：测试连接</strong></p><p>点击 <strong>测试连接</strong> 按钮，验证 MPC-BE 的 Web 接口是否能正常通信。连接成功后状态会变为 &quot;已连接&quot;。</p><blockquote><p>TODO: 截图 - 连接状态从&quot;未连接&quot;变为&quot;已连接&quot;</p></blockquote><h4 id="覆盖区域裁切" tabindex="-1">覆盖区域裁切 <a class="header-anchor" href="#覆盖区域裁切" aria-label="Permalink to &quot;覆盖区域裁切&quot;">​</a></h4><p>由于 MPC-BE 窗口包含菜单栏和控制栏，需要裁切掉这些区域，让弹幕只显示在视频画面上。</p><table tabindex="0"><thead><tr><th>配置项</th><th>说明</th></tr></thead><tbody><tr><td>上边距</td><td>排除菜单栏/标题栏的高度（像素），一般为 30-50px</td></tr><tr><td>下边距</td><td>排除控制栏的高度（像素），一般为 40-60px</td></tr></tbody></table><blockquote><p>TODO: 截图 - 覆盖区域裁切配置</p></blockquote><p>在进入全屏模式时，系统会自动忽略上边距和下边距（或使用全屏专用的偏移值），弹幕铺满全屏。</p><h4 id="启动弹幕覆盖" tabindex="-1">启动弹幕覆盖 <a class="header-anchor" href="#启动弹幕覆盖" aria-label="Permalink to &quot;启动弹幕覆盖&quot;">​</a></h4><p>确认满足以下条件后点击 <strong>启动弹幕覆盖</strong>：</p><ul><li>已加载 ASS 弹幕文件</li><li>已选择播放器窗口</li><li>Web 端口测试连接成功</li></ul><p>启动后，弹幕覆盖窗口会悬浮在 MPC-BE 上方，弹幕随播放进度实时同步。</p><h4 id="播放状态监控" tabindex="-1">播放状态监控 <a class="header-anchor" href="#播放状态监控" aria-label="Permalink to &quot;播放状态监控&quot;">​</a></h4><p>外部播放器模式提供实时播放状态面板：</p><ul><li><strong>正在播放/已暂停/已停止</strong>：当前播放状态</li><li><strong>当前文件</strong>：MPC-BE 正在播放的文件名</li><li><strong>播放进度</strong>：当前时间 / 总时长</li><li><strong>覆盖窗口状态</strong>：显示覆盖窗口是否已激活、位置同步中</li></ul><blockquote><p>TODO: 截图 - 播放状态面板</p></blockquote><h3 id="弹幕显示设置" tabindex="-1">弹幕显示设置 <a class="header-anchor" href="#弹幕显示设置" aria-label="Permalink to &quot;弹幕显示设置&quot;">​</a></h3><p>弹幕设置面板提供丰富的显示调整选项，所有设置都会<strong>实时生效</strong>并<strong>自动保存</strong>，下次打开工具时自动恢复。</p><blockquote><p>TODO: 截图 - 弹幕显示设置面板，标注各控件</p></blockquote><h4 id="基本设置" tabindex="-1">基本设置 <a class="header-anchor" href="#基本设置" aria-label="Permalink to &quot;基本设置&quot;">​</a></h4><table tabindex="0"><thead><tr><th>设置</th><th>说明</th></tr></thead><tbody><tr><td>弹幕开关</td><td>一键隐藏/显示所有弹幕</td></tr><tr><td>滚动弹幕</td><td>控制从右到左滚动的弹幕是否显示</td></tr><tr><td>固定弹幕</td><td>控制固定在画面顶部/底部的弹幕是否显示</td></tr><tr><td>彩色弹幕</td><td>控制非白色的彩色弹幕是否显示</td></tr></tbody></table><h4 id="显示调整" tabindex="-1">显示调整 <a class="header-anchor" href="#显示调整" aria-label="Permalink to &quot;显示调整&quot;">​</a></h4><table tabindex="0"><thead><tr><th>设置</th><th>范围</th><th>说明</th></tr></thead><tbody><tr><td>显示区域</td><td>0-100%</td><td>弹幕在画面中垂直方向占用的比例，100% 即满屏</td></tr><tr><td>透明度</td><td>0-100%</td><td>弹幕整体的透明度，数值越大越不透明</td></tr><tr><td>字体缩放</td><td>50-200%</td><td>弹幕字体的缩放比例</td></tr><tr><td>速度</td><td>0.5-2.0x</td><td>滚动弹幕的移动速度，越大越快</td></tr></tbody></table><h4 id="密度控制" tabindex="-1">密度控制 <a class="header-anchor" href="#密度控制" aria-label="Permalink to &quot;密度控制&quot;">​</a></h4><p><strong>密度</strong> 滑块控制同时显示的弹幕数量（0-100%）。100% 为全量显示，数值越低，屏幕上显示的弹幕越稀疏。</p><p>密度过滤采用<strong>稳定哈希算法</strong>——相同内容的弹幕会优先保留或过滤，切换帧时不会出现内容随机抖动。</p><h4 id="屏蔽词" tabindex="-1">屏蔽词 <a class="header-anchor" href="#屏蔽词" aria-label="Permalink to &quot;屏蔽词&quot;">​</a></h4><p>在屏蔽词输入框中输入关键词（每行一个），包含这些关键词的弹幕将不会显示。这在过滤剧透、广告或不需要的弹幕时非常有用。</p><blockquote><p>TODO: 截图 - 屏蔽词输入框</p></blockquote><h4 id="高级样式" tabindex="-1">高级样式 <a class="header-anchor" href="#高级样式" aria-label="Permalink to &quot;高级样式&quot;">​</a></h4><table tabindex="0"><thead><tr><th>设置</th><th>说明</th></tr></thead><tbody><tr><td>字体</td><td>弹幕显示的字体（如 &quot;Microsoft YaHei&quot;）</td></tr><tr><td>加粗</td><td>所有弹幕统一加粗</td></tr><tr><td>边框类型</td><td>发光（Glow）：同色柔和发光 / 描边（Outline）：黑色描边 / 阴影（Shadow）：右下黑色投影</td></tr></tbody></table><h2 id="高级用法" tabindex="-1">高级用法 <a class="header-anchor" href="#高级用法" aria-label="Permalink to &quot;高级用法&quot;">​</a></h2><h3 id="自定义弹幕样式精确调整" tabindex="-1">自定义弹幕样式精确调整 <a class="header-anchor" href="#自定义弹幕样式精确调整" aria-label="Permalink to &quot;自定义弹幕样式精确调整&quot;">​</a></h3><p>通过组合使用弹幕设置面板中的各项参数，你可以调出完全属于自己的弹幕风格：</p><ul><li><strong>暗色视频</strong>：提高透明度（80-90%）+ 发光边框，弹幕既清晰又不遮住画面</li><li><strong>高信息量视频</strong>：降低密度（60-70%）+ 开启固定弹幕过滤，避免弹幕遮挡重要内容</li><li><strong>老番回顾</strong>：降低速度（0.7-0.8x）+ 增大字体（120-140%），看得更从容</li></ul><h3 id="使用屏蔽词过滤剧透" tabindex="-1">使用屏蔽词过滤剧透 <a class="header-anchor" href="#使用屏蔽词过滤剧透" aria-label="Permalink to &quot;使用屏蔽词过滤剧透&quot;">​</a></h3><p>在追新番或看剧情类视频时，开启屏蔽词过滤可以避免被弹幕剧透：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>剧透警告</span></span>
<span class="line"><span>后面会死</span></span>
<span class="line"><span>凶手是</span></span>
<span class="line"><span>下集预告</span></span></code></pre></div><p>每个关键词占一行，系统会自动跳过包含这些词的弹幕。</p><h3 id="外部播放器全屏增强" tabindex="-1">外部播放器全屏增强 <a class="header-anchor" href="#外部播放器全屏增强" aria-label="Permalink to &quot;外部播放器全屏增强&quot;">​</a></h3><p>在使用 MPC-BE 全屏播放时，开启 <strong>全屏覆盖增强（强制置顶）</strong> 选项可以确保弹幕覆盖窗口始终显示在视频上层，避免在全屏切换时被遮挡。</p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-ass-弹幕文件从哪里获取" tabindex="-1">Q：ASS 弹幕文件从哪里获取？ <a class="header-anchor" href="#q-ass-弹幕文件从哪里获取" aria-label="Permalink to &quot;Q：ASS 弹幕文件从哪里获取？&quot;">​</a></h3><p>ASS 弹幕文件最常用的来源是 <strong>Bilibili Evolved</strong>（简称 Bilibili EV）。这是一个浏览器扩展，安装后在 B 站视频页面可以看到一个&quot;导出弹幕&quot;的按钮，可以选择导出为 ASS 格式。</p><p>另外，你也可以使用其他第三方工具从各大视频网站下载弹幕并转换为 ASS 格式。</p><h3 id="q-为什么加载弹幕文件后-部分弹幕没有显示" tabindex="-1">Q：为什么加载弹幕文件后，部分弹幕没有显示？ <a class="header-anchor" href="#q-为什么加载弹幕文件后-部分弹幕没有显示" aria-label="Permalink to &quot;Q：为什么加载弹幕文件后，部分弹幕没有显示？&quot;">​</a></h3><p>可能的原因：</p><ol><li><strong>类型过滤被关闭</strong>：检查设置面板中&quot;滚动弹幕&quot;和&quot;固定弹幕&quot;是否都已开启</li><li><strong>密度值太低</strong>：如果密度设置过低，系统会按哈希值随机跳过部分弹幕</li><li><strong>显示区域太小</strong>：显示区域设置控制弹幕的可视区域比例，值太小会导致上部弹幕被裁切</li><li><strong>有屏蔽词匹配</strong>：检查屏蔽词列表中是否有误伤的关键词</li></ol><h3 id="q-外部播放器模式下-弹幕覆盖窗口位置不对" tabindex="-1">Q：外部播放器模式下，弹幕覆盖窗口位置不对？ <a class="header-anchor" href="#q-外部播放器模式下-弹幕覆盖窗口位置不对" aria-label="Permalink to &quot;Q：外部播放器模式下，弹幕覆盖窗口位置不对？&quot;">​</a></h3><p>这通常是因为覆盖区域裁切的边距设置不合适：</p><ol><li>在外部播放器设置中调整 <strong>上边距</strong> 和 <strong>下边距</strong> 的像素值</li><li>如果全屏模式下位置不对，调整 <strong>全屏偏移</strong> 的相关设置</li><li>确保 MPC-BE 的窗口没有被其他窗口部分遮挡</li></ol><h3 id="q-弹幕遮挡了字幕怎么办" tabindex="-1">Q：弹幕遮挡了字幕怎么办？ <a class="header-anchor" href="#q-弹幕遮挡了字幕怎么办" aria-label="Permalink to &quot;Q：弹幕遮挡了字幕怎么办？&quot;">​</a></h3><p>弹幕可能会遮挡视频本身的内嵌字幕。目前可以通过以下方式缓解：</p><ol><li>降低 <strong>显示区域</strong> 的比例（如 40-50%），让弹幕集中在画面底部</li><li>提高 <strong>透明度</strong>，让弹幕半透明化，减少遮挡感</li><li>在弹幕设置中勾选 <strong>防止遮挡字幕</strong>（如果有此选项）</li></ol><h3 id="q-可以同时加载多个-ass-弹幕文件吗" tabindex="-1">Q：可以同时加载多个 ASS 弹幕文件吗？ <a class="header-anchor" href="#q-可以同时加载多个-ass-弹幕文件吗" aria-label="Permalink to &quot;Q：可以同时加载多个 ASS 弹幕文件吗？&quot;">​</a></h3><p>目前弹幕播放器一次只支持加载一个 ASS 弹幕文件。如果需要合并多个弹幕文件，可以先用第三方工具将多个 ASS 文件合并，再加载到播放器中。</p><div class="tip custom-block"><p class="custom-block-title">提示</p><p>弹幕播放器是您本地视频的最佳伴侣，支持自定义弹幕样式、过滤屏蔽内容和多模式播放。祝您观影愉快！</p></div>`,111)])])}const b=a(l,[["render",i]]);export{c as __pageData,b as default};
